from dataclasses import dataclass
from typing import Callable

@dataclass
class FilterResult:
    blocked: bool
    reason: str = ''
    latency_ms: float = 0.0

class FilterPipeline:
    def __init__(self):
        # Ordered from fastest/cheapest to slowest/most accurate
        self.input_filters:  list[Callable] = []
        self.output_filters: list[Callable] = []

    def add_input_filter(self, fn): self.input_filters.append(fn)
    def add_output_filter(self, fn): self.output_filters.append(fn)

    def check_input(self, text: str) -> FilterResult:
        for fn in self.input_filters:
            result = fn(text)
            if result.blocked:
                return result
        return FilterResult(blocked=False)

    def check_output(self, text: str) -> FilterResult:
        for fn in self.output_filters:
            result = fn(text)
            if result.blocked:
                return result
        return FilterResult(blocked=False)

